update tags set description = 'Prevents the affected Champion from using PASSIVE skills (other than their default and active skills) for the duration. Cooldowns refresh as normal. Does NOT work on bosses (→ useless vs a dungeon boss; only vs minions/waves/PvP).' where name = 'Block Passive Skills' and game_id = 'raid_shadow_legends';
update tags set description = 'When attacked, strikes back at the attacker with their Default Skill for 75% damage. Only counters once vs a multi-hit skill. Does not counter a counterattack. Does not count as a turn. Extra-Turn-on-kill default skills do NOT grant the extra turn during a counter.' where name = 'Counterattack' and game_id = 'raid_shadow_legends';
