update tags set description = 'Decreases Critical Rate by 15% or 30%.' where name = 'Decrease C.Rate' and game_id = 'raid_shadow_legends';
update tags set description = 'Decreases Battle Defense by 30/60%. (Amplifies ATTACK damage only — NOT DoT; see damage-mechanics §1.)' where name = 'Decrease Defense' and game_id = 'raid_shadow_legends';
update tags set description = 'Decreases Battle Resistance by 25% or 50% — makes landing debuffs easier (less ACC required).' where name = 'Decrease RES' and game_id = 'raid_shadow_legends';
update tags set description = 'Decreases Battle Speed by 15/30%.' where name = 'Decrease Speed' and game_id = 'raid_shadow_legends';
